"use strict";(globalThis.webpackChunktanyaacjain_github_io=globalThis.webpackChunktanyaacjain_github_io||[]).push([[4257],{785:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>o,default:()=>d,frontMatter:()=>s,metadata:()=>r,toc:()=>l});var i=n(4848),a=n(8453);const s={title:"The Cost of Trusting Oneself",authors:"tanya",date:new Date("2018-12-01T00:00:00.000Z"),tags:["reflections"]},o=void 0,r={permalink:"/writings/cost-of-trust",source:"@site/writings/cost-of-trust.md",title:"The Cost of Trusting Oneself",description:"A story about a Prime Minister\u2019s felicitation, family doubt, and learning to trust my own compass",date:"2018-12-01T00:00:00.000Z",tags:[{inline:!1,label:"Reflections",permalink:"/writings/tags/reflections",description:"Things reflected upon"}],readingTime:4.21,hasTruncateMarker:!1,authors:[{name:"Tanya Jain",title:"Author",url:"https://github.com/tanyaacjain",socials:{x:"tanyaacjain",github:"tanyaacjain"},imageURL:"https://github.com/tanyaacjain.png",key:"tanya"}],frontMatter:{title:"The Cost of Trusting Oneself",authors:"tanya",date:"2018-12-01T00:00:00.000Z",tags:["reflections"]},unlisted:!1,prevItem:{title:"My Journey Into Tech",permalink:"/writings/starting-off-in-tech"}},h={authorsImageUrls:[void 0]},l=[];function c(e){const t={em:"em",hr:"hr",p:"p",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:(0,i.jsx)(t.em,{children:"A story about a Prime Minister\u2019s felicitation, family doubt, and learning to trust my own compass"})}),"\n",(0,i.jsx)(t.p,{children:"When I was starting high school, I was at crossroads of chosing a stream of courses, as goes in the Indian education system. I had to decide between studying either economics or computer science. AI hadn\u2019t yet become a household buzzword. My family, with roots in multi-industry business, saw computer science as a narrow, uncertain path, especially when not having enough examples in their experiences to validate the path. Economics, on the other hand, was respectable, versatile, safe and would most importantly keep the doors wide open, in a traditional sense, for all of business, academia and government services."}),"\n",(0,i.jsx)(t.p,{children:"I chose computer science."}),"\n",(0,i.jsxs)(t.p,{children:["My reasoning was mainly a hidden passion with a flavor of practicality that computer science is a skill\u2011based knowledge. While I spent my afternoons and nights tinkering with my personal computer, I could see myself wanting to learn it deeply under structured guidance and practice. Economics, I believed, was something I could pick up later if I chose to run a business, through life. ",(0,i.jsx)("sup",{children:"[1]"})," I couldn\u2019t explain this well at sixteen. I only knew I had to try."]}),"\n",(0,i.jsxs)(t.p,{children:["The skepticism was polite at first, then persistent.\xa0",(0,i.jsx)(t.em,{children:"\u201cAre you sure? You might regret this.\u201d"}),"\xa0I wasn\u2019t sure, how well my statements made sense. I just knew I have always had a lovely relationship with computers and I would like to maintain it."]}),"\n",(0,i.jsx)(t.p,{children:"Years later, when high school was done where I had performed the highest in the computer science subject than any other, and now I was in uni pursuing my Bachelors in the subject, I came across an email that I would brush off in a first glance as spam."}),"\n",(0,i.jsx)(t.p,{children:"I had been selected for felicitation by Narendra Modi, the Prime Minister of India at the time, for one of the early active participation in digital governance. The invitation felt surreal. I told my parents as they lived through their usual, rushed daily life, brushing it off as spam without even looking at the screen. Digital scams were really too active then and it was an extraordinary claim to accept when not having seen a physical evidence. So I didn\u2019t go."}),"\n",(0,i.jsxs)(t.p,{children:["Weeks later, the ceremony aired on national television. My family was gathered in the living room when the segment began. There, on screen, were the dignitaries, the venue, the very event I had described. Looking at fellows get felicitated by the Prime Minister, my dad turned to me.\xa0",(0,i.jsx)(t.em,{children:"\u201cWhy aren\u2019t you doing such rewarding deeds?\u201d"})]}),"\n",(0,i.jsx)(t.p,{children:"I exclaimed, \u201cYou called it a scam when I told you!\u201d. A little sheepishly with a hint of pride they looked at the email that I hadn\u2019t yet deleted."}),"\n",(0,i.jsx)(t.p,{children:"Did my family stop questioning my plans after that? Not entirely. The pattern had started earlier, and it would continue."}),"\n",(0,i.jsx)(t.p,{children:"In college, I threw myself into building ALiAS, a community for Linux and open\u2011source enthusiasts. I organized events, attended meetups, spent evenings in empty classrooms talking about kernels and pull requests. To my family, it looked like I was spending time and money on something with no clear return."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.em,{children:"\u201cShouldn\u2019t you focus on your studies?\u201d"}),"\xa0they\u2019d ask.\xa0",(0,i.jsx)(t.em,{children:"\u201cIs this really worth it?\u201d"})]}),"\n",(0,i.jsx)(t.p,{children:"I didn\u2019t have an answer that would satisfy them. I only knew that building something alongside passionate people felt more valuable than any grade. So I kept going."}),"\n",(0,i.jsx)(t.p,{children:"Over time, the community grew. ALiAS became the most active tech club on campus. We introduced Python into the university curriculum. Students made their first open\u2011source contributions. Chapters began appearing in other cities. The recognition came, not just in awards like the Shri Baljit Shastri Award for being the Best in Human Values in my entire university, but in the quiet satisfaction of seeing me mentor others and help them come out of problems I was once drowned in."}),"\n",(0,i.jsx)(t.p,{children:"My family saw it, too. The same relatives who had questioned my choice of computer science began pursuing master\u2019s degrees in the field. The same parents who doubted the value of my \u201cmeetings\u201d started asking about the next event.\nThey didn\u2019t apologize. That\u2019s not how it works in an Asian household. But they no longer doubted."}),"\n",(0,i.jsx)(t.p,{children:"My family, like any higher genration, wanted me to be safe externally while I was chosing it in trusting my own compass even when the map was unclear."}),"\n",(0,i.jsx)(t.p,{children:"Now, when I make a decision that looks uncertain from the outside, I welcome the questions. They help me see perspectives I might have missed. The final direction comes from within."}),"\n",(0,i.jsx)(t.p,{children:"Reflecting, when I see someone navigate a similarly uncertain path, I aim to offer what I would need, that is, trust without the wight of conditions."}),"\n",(0,i.jsx)(t.p,{children:"Patience, though not easy, is well worth it when doing the slow, steady work of building something worth believing in."}),"\n",(0,i.jsx)(t.p,{children:"Eventually, the evidence arrives on its own. You just need to show up."}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.p,{children:"[1]: Here, the value of economics in my life was put up for more on-ground applicability like running a business, rather than an in-depth understanding of the subject."})]})}function d(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>o,x:()=>r});var i=n(6540);const a={},s=i.createContext(a);function o(e){const t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),i.createElement(s.Provider,{value:t},e.children)}}}]);